import type { DbDriver, HealthTargets } from '@motivation/shared';
import {
    DEFAULT_HEALTH_TARGETS,
    HEALTH_CALORIE_BUDGET_KEY,
    HEALTH_PROTEIN_TARGET_KEY,
    HEALTH_STEP_GOAL_KEY,
} from '@motivation/shared';
import { DbService } from '../db/db.service.js';

/**
 * Story 258 — the user's health targets (calorie budget, protein target,
 * step goal), persisted as synced `settings` rows so the server can read
 * them later (same mechanism as `app.timezone`, story 169).
 *
 * Targets are cached in memory so render code reads them synchronously;
 * before `init()` the cache holds the documented defaults. `init()` also
 * performs the one-time migration of the legacy trend-chart localStorage
 * calorie target into the synced row (an existing settings row wins), then
 * removes the localStorage key either way.
 */

export const LEGACY_CALORIE_TARGET_STORAGE_KEY = 'health_calorie_target';

const SETTINGS_UPSERT = `INSERT INTO settings (key, value) VALUES (?, ?)
                 ON CONFLICT(key) DO UPDATE SET value = excluded.value, updated_at = datetime('now')`;

const TARGET_KEYS: Record<keyof HealthTargets, string> = {
    calorie_budget_kcal: HEALTH_CALORIE_BUDGET_KEY,
    protein_target_g: HEALTH_PROTEIN_TARGET_KEY,
    step_goal: HEALTH_STEP_GOAL_KEY,
};

export interface HealthTargetsServiceDeps {
    driver?: () => Promise<DbDriver>;
    /** Legacy-migration source — injectable for tests. */
    storage?: Pick<Storage, 'getItem' | 'removeItem'>;
}

async function defaultDriver(): Promise<DbDriver> {
    const service = DbService.getInstance();
    await service.init();
    return service.driver;
}

function parsePositive(value: string | null): number | null {
    if (value === null) return null;
    const parsed = Number(value);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
}

export class HealthTargetsService {
    private readonly driverFn: () => Promise<DbDriver>;
    private readonly storage: Pick<Storage, 'getItem' | 'removeItem'>;
    private targets: HealthTargets = { ...DEFAULT_HEALTH_TARGETS };
    private readonly listeners = new Set<() => void>();

    constructor(deps: HealthTargetsServiceDeps = {}) {
        this.driverFn = deps.driver ?? defaultDriver;
        this.storage = deps.storage ?? localStorage;
    }

    /** Synchronous accessor for render code. Defaults before init(). */
    getTargets(): HealthTargets {
        return { ...this.targets };
    }

    /**
     * Re-render hook: fires after init() resolves the synced rows and after
     * every setTargets(). Components render synchronously from getTargets(),
     * so the boot race (screen paints before init lands) and cross-screen
     * edits both need this signal. Returns the unsubscribe function.
     */
    onChange(listener: () => void): () => void {
        this.listeners.add(listener);
        return () => this.listeners.delete(listener);
    }

    private notify(): void {
        for (const listener of this.listeners) listener();
    }

    async init(): Promise<void> {
        const driver = await this.driverFn();
        await this.migrateLegacyCalorieTarget(driver);
        const [budget, protein, steps] = await Promise.all([
            this.read(driver, HEALTH_CALORIE_BUDGET_KEY),
            this.read(driver, HEALTH_PROTEIN_TARGET_KEY),
            this.read(driver, HEALTH_STEP_GOAL_KEY),
        ]);
        this.targets = {
            calorie_budget_kcal: parsePositive(budget) ?? DEFAULT_HEALTH_TARGETS.calorie_budget_kcal,
            protein_target_g: parsePositive(protein) ?? DEFAULT_HEALTH_TARGETS.protein_target_g,
            step_goal: parsePositive(steps) ?? DEFAULT_HEALTH_TARGETS.step_goal,
        };
        this.notify();
    }

    async setTargets(partial: Partial<HealthTargets>): Promise<void> {
        const driver = await this.driverFn();
        for (const [field, value] of Object.entries(partial) as Array<[keyof HealthTargets, number]>) {
            if (!Number.isFinite(value) || value <= 0) {
                throw new Error(`health target ${field} must be a positive number, got ${value}`);
            }
            await driver.execute(SETTINGS_UPSERT, TARGET_KEYS[field], String(value));
            this.targets[field] = value;
        }
        this.notify();
    }

    /**
     * One-time move of the pre-258 trend-chart target out of localStorage.
     * A synced settings row always wins; the legacy key is removed either way.
     */
    private async migrateLegacyCalorieTarget(driver: DbDriver): Promise<void> {
        const legacy = parsePositive(this.storage.getItem(LEGACY_CALORIE_TARGET_STORAGE_KEY));
        if (legacy === null) return;
        const stored = await this.read(driver, HEALTH_CALORIE_BUDGET_KEY);
        if (stored === null) {
            await driver.execute(SETTINGS_UPSERT, HEALTH_CALORIE_BUDGET_KEY, String(legacy));
        }
        this.storage.removeItem(LEGACY_CALORIE_TARGET_STORAGE_KEY);
    }

    private async read(driver: DbDriver, key: string): Promise<string | null> {
        const rows = await driver.query<{ value: string }>('SELECT value FROM settings WHERE key = ?', key);
        return rows[0]?.value ?? null;
    }
}

export const healthTargetsService = new HealthTargetsService();

/** Synchronous targets accessor for render code across the health section. */
export function getHealthTargets(): HealthTargets {
    return healthTargetsService.getTargets();
}

/** Boot hook — call once after the local DB is ready. */
export function initHealthTargets(): Promise<void> {
    return healthTargetsService.init();
}
